INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-02336', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列那項敘述，比較貼近格林伍德（Ernest Greenwood）對於專業特質的闡釋？', '["一個專業應該有其基本知識並發展出系統的理論來引導實務工作的說法，忽略了自然助人法", "一個專業應該避免建立用以規範自身社群的各式標準，以防止專業造成自身的壓迫", "一個專業只要具強制力的、明確的、和有系統的倫理守則，就是一種權力的宰制", "一個專業必須在正式與非正式的組織網絡中提供文化價值、規範及象徵，以便發揮其功能與成效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02337', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「與其讓人們變成遊民之後，再為他們找住宿的地方；不如付比較多的稅，蓋足夠而且價格合理的房子， 防止人們變成遊民」。以上敘述，比較傾向下列那一種觀點？', '["制度式", "殘補式", "選擇式", "混合式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02338', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「重視服務使用者的優勢、強調合作關係、看重對結構的反思，以及試圖連結個人與政治權力」的敘述， 比較傾向下列那一項觀點？', '["控制", "功能", "充權", "病理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02339', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關社會工作中「外借理論」與「實施理論」的敘述，何者正確？', '["可以幫助我們對人際關係和社會現象理解的，稱為實施理論", "可以改變行為、社會體系達成社會工作目標的，稱為外借理論", "實施理論關心人類行為與社會環境關係本質的了解，又稱預估理論", "任務中心、問題解決、危機干預屬於實施理論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02340', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「參加某考試，不幸沒通過。就說是自己不想要，沒盡力爭取」。這項敘述，比較傾向下列那種防衛機 轉的使用？', '["否認（denial）", "認同（identification）", "潛抑（repression）", "合理化（rationalization）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02341', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關心理暨社會學派中「直接影響技術（procedures of direct influence）」的說明，何者正確？', '["這項技術關心協助案主對自身憤怒、焦慮與罪惡感，進行描述與討論，促使情緒的宣洩是主要目的", "它是社會工作者對案主所應採取行動的意見表達，其效力有賴案主與社會工作者間彼此正向關係的強度", "在進行討論性會談時，一般而言無須支持性的技術為後盾，可以直接應用本技術", "在近年研究中，直接影響技術因抵觸案主自決原則，其效果如同早先所想像般無效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02342', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列「危機介入取向（crisis intervention）」的敘述，何者正確？', '["它是種經由教育訓練、資源提供等方法，使用長期處遇，協助個人恢復乃至增進其生活適應功能的方法", "諸如風災、土石流，乃至大規模的恐怖攻擊，容易在人生的轉捩點上帶來發展性的危機", "危機情境是一種個人病態所引發的生、心理疾病反應，它的歷程很長並且因人而異，不易預測", "危機介入過程要不斷評估案主系統現有的以及潛在可能受到的傷害，並提供保護性措施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02343', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列「任務中心取向（task-centered approach）」的敘述，何者正確？', '["它假定人有改變動力，問題須由服務使用者自己界定，而短期和時間限制是其特色", "透過雙方對於任務內容的討論，特別適用於處理尋求意義型，以及缺乏動機型的個案", "任務是達成目標的最後結果，目標是要做什麼的具體陳述", "與功能派社會工作觀點類似，它透過生態的有機比擬說來理解人類行為與社會環境"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02344', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列社會工作理論或觀點對人的問題的敘述，何者正確？', '["心理暨社會學派傾向認為人的問題全部來自早期未竟事宜所引發的內在心理衝突與自我防衛機轉失靈", "生態系統觀點傾向認為人的問題來自非理性的信念與不良的自我功能", "增強權能觀點傾向認為人的問題來自長期負面評價所帶來的個人心理無力感，及優勢團體壓迫所帶來 的機會剝奪", "社會網絡處遇學派傾向認為人的問題來自資本主義政治經濟結構對於弱勢群體所帶來的不公"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02345', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在認知行為學派、社會網絡處遇學派與基變觀點中，社會工作者所扮演的主要角色組合，何者正確？', '["認知行為學派：教練與正向經驗伙伴；社會網絡處遇學派：資源與人際連結者；基變觀點：社會教育 與行動者", "認知行為學派：各個次系統的聯結者；社會網絡處遇學派：服務契約訂定者；基變觀點：正向心理學 的支持者", "認知行為學派：協同工作的組織者；社會網絡處遇學派：內在行為修正的使能者；基變觀點：同理分 析情感修正者", "認知行為學派：平等充權的行動夥伴；社會網絡處遇學派：行動改造的倡議者；基變觀點：積極變遷 的指導者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02346', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「某位房東拒絕把房子租給同性戀者」，其做法比較傾向下列那種描述？', '["投射（projection）", "歧視（discrimination）", "充權（empowerment）", "結構洞（structural holes）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02347', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '針對工作能力不足以獨立完成工作的身障者，提供工作技能、提升產能、建立人際關係、工作行為與態 度，乃至交通訓練的社區化就業輔導，是下列那項服務模式的主要工作內容？', '["競爭性", "支持性", "庇護性", "安置性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02348', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '經社會工作者評估兒童及少年可以繼續留在原生家庭中；但須引進資源，協助家庭成員提升親職教養能 力，以便保持家庭功能及完整性的干預方式，稱為？', '["家庭星座（family constellation）", "家庭重整（family reunification）", "家庭維繫（family preservation）", "家庭系譜（genealogy）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02349', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關老人虐待類型的敘述，何者錯誤？', '["因疏忽或故意，致使老人身體或身體功能遭受傷害的行為，屬於身體型的虐待", "透過言語或行為，造成老人心理及情緒上極度之痛苦或恐慌，屬於照顧者疏忽型的虐待", "依法令或契約有扶養義務而不予以適當照顧，任老人流落街頭，屬於遺棄型的虐待", "對精神耗弱不能處理自己事務之老人，非法侵占他的財產，屬於財產剝奪型的虐待"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02350', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在提供充分資訊，協助析辨利害得失，並且明白相關替代方案及其後果之後，服務使用者仍然做出不利 自身福祉的選擇。社會工作者對此表示尊重，這是基於瑞摩（Reamer）那一項倫理困境抉擇原則的應用？', '["個人自我決定權優先於自身基本福祉權", "個人自由意志下同意遵守之義務優先於個人信仰與價值", "個人基本福祉權優於守法的義務", "公共利益優於保障個人財產權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
